const msg = $input.first().json;
const content = (msg.content || '').trim();
const channelId = msg.channelId || msg.channel_id || '';

if (!content.startsWith('!podcast')) return [];

// Parse: !podcast [topic] for:[client] tone:[solo|interview] length:[short|medium]
const text = content.replace('!podcast', '').trim();

// Extract optional flags
const forMatch = text.match(/for:([\w\s-]+?)(?=tone:|length:|$)/i);
const toneMatch = text.match(/tone:(solo|interview)/i);
const lengthMatch = text.match(/length:(short|medium)/i);

// Remove flags from topic
const topic = text
  .replace(/for:[\w\s-]+/i, '')
  .replace(/tone:(solo|interview)/i, '')
  .replace(/length:(short|medium)/i, '')
  .trim();

const client = forMatch ? forMatch[1].trim() : 'general';
const tone = toneMatch ? toneMatch[1].toLowerCase() : 'solo';
const length = lengthMatch ? lengthMatch[1].toLowerCase() : 'short';

const wordCount = length === 'medium' ? 600 : 300;

return [{ json: { topic, client, tone, length, wordCount, channelId } }];

