const response = $input.first().json;
const briefData = $('Extract Brief').item.json;

// Extract text from GPT-4o mini response
const script = response.choices?.[0]?.message?.content || '';

// Clean for TTS — strip speaker labels and stage directions
const ttsScript = script
  .replace(/\[.*?\]/g, '')
  .replace(/\*.*?\*/g, '')
  .replace(/^(HOST|EXPERT|THERRANCE):\s*/gim, '')
  .replace(/\n{3,}/g, '\n\n')
  .trim();

return [{
  json: {
    script,
    ttsScript,
    topic: briefData.topic,
    client: briefData.client,
    tone: briefData.tone,
    channelId: briefData.channelId,
    filename: `thurnos-podcast-${briefData.topic.toLowerCase().replace(/\s+/g, '-').slice(0,40)}-${Date.now()}.mp3`
  }
}];

const driveFile = $input.first().json;
const scriptData = $('Extract Script').item.json;

const fileId = driveFile.id || driveFile.fileId || '';
const fileName = driveFile.name || scriptData.filename;
